#include<bits/stdc++.h>
using namespace std;
int n,m;
struct node
{
    int a[5001],len;
    node()
    {
        memset(a,0,sizeof(0));
        len=0;
    }
    void operator=(int x)
    {
        int cnt=0;
        while(x)
        {
            a[++cnt]=x%10;
            x/=10;
        }
        len=cnt;
    }
    node operator*(const int&b)const
    {
        node c;
        memcpy(c.a,a,sizeof(a));
        for(int i=1;i<=len;i++)
        {
            c.a[i]*=b;
        }
        int l=0;
        for(int i=1;i<=len+50;i++)
        {
            if(c.a[i])
            {
                l=i;
            }
            c.a[i+1]+=c.a[i]/10;
            c.a[i]%=10;
        }
        c.len=l;
        return c;
    }
    node operator+(const node&b)const
    {
        int l=max(len,b.len);
        node c;
        memset(c.a,0,sizeof(c.a));
        for(int i=1;i<=l;i++)
        {
            c.a[i]+=a[i]+b.a[i];
            c.a[i+1]+=c.a[i]/10;
            c.a[i]%=10;
        }
        if(c.a[l+1]!=0)
        {
            l++;
        }
        c.len=l;
        return c;
    }
    void print()const
    {
        int cnt=len;
        if(cnt==0)
        {
            printf("0");
        }
        else
        {
            for(int i=cnt;i>=1;i--)
            {
                printf("%d",a[i]);
            }
        }
    }
};
